    fn dispatchCsi(self: *Parser, final: u8) InputEvent {
        const event = InputEvent{ .csi = .{
            .final = final,
            .intermediates = self.intermediates,
            .intermediate_count = self.intermediate_count,
            .params = self.params,
            .param_count = self.param_count,
