        if (self.osc_len < self.osc_buf.len) {
            self.osc_buf[self.osc_len] = byte;
            self.osc_len += 1;
        }
        return null;
    }

    fn dispatchOsc(self: *Parser) InputEvent {
        var osc = OSC{ .ps = self.osc_ps };
